// ─── Socket singleton ─────────────────────────────────────────────────────────
let socket = null;
const getSocket = () => {
  if (!socket) {
    socket = io(process.env.REACT_APP_SOCKET_URL || "https://capavate.com", {
      transports: ["websocket"],
      autoConnect: true,
    });
  }
  return socket;
};

// ─── Helpers ──────────────────────────────────────────────────────────────────
const timeAgo = (dateStr) => {
  if (!dateStr) return "";
  const diff = (Date.now() - new Date(dateStr)) / 1000;
  if (diff < 60) return "just now";
  if (diff < 3600) return `${Math.floor(diff / 60)}m ago`;
  if (diff < 86400) return `${Math.floor(diff / 3600)}h ago`;
  return `${Math.floor(diff / 86400)}d ago`;
};

const parseImages = (post) => {
  const addBase = (img) => {
    if (!img) return img;
    if (img.startsWith("http")) return img;
    // ✅ relative path mein API base add karo
    const base = (API_BASE_URL || "https://capavate.com/api/").replace(/\/$/, "");
    return `${base}${img.startsWith("/") ? "" : "/"}${img}`;
  };

  if (post.images && Array.isArray(post.images) && post.images.length > 0)
    return post.images.map(addBase);
  if (post.image_urls) {
    try {
      const parsed =
        typeof post.image_urls === "string"
          ? JSON.parse(post.image_urls)
          : post.image_urls;
      return Array.isArray(parsed) ? parsed.map(addBase) : [];
    } catch {
      return [];
    }
  }
  return [];
};

const normalizePost = (p) => ({
  ...p,
  liked: p.liked || p.is_liked === 1 || false,
  followed: p.followed || p.is_following === 1 || false,
  is_pinned: p.is_pinned === 1 || p.is_pinned === true || false,
  commentsList: [],
  likes: p.likes || p.likes_count || 0,
  comments: p.comments || p.comments_count || 0,
  images: parseImages(p),
});

// ─── Sender label helper ─────────────────────────────────────────────────────
const getSenderInfo = (post) => {
  const cat = post.sender_category;
  const region = post.author_region;
  const company = post.shared_company_name;

  if (cat === "own") return null;

  if (cat === "portfolio_company") {
    return {
      label: "Portfolio Company",
      sublabel: null,
      color: "#1565c0",
      bg: "#e3f2fd",
      border: "#90caf9",
      icon: "🏢",
    };
  }
  if (cat === "fellow_shareholder") {
    return {
      label: "Fellow Shareholder",
      sublabel: company || null,
      color: "#6a1b9a",
      bg: "#f3e5f5",
      border: "#ce93d8",
      icon: "🤝",
    };
  }
  if (cat === "angel_network") {
    return {
      label: `Capavate Angel Network${region ? ` · ${region}` : ""}`,
      sublabel: null,
      color: "#e65100",
      bg: "#fff3e0",
      border: "#ffcc80",
      icon: "👼",
    };
  }
  return {
    label: "Social Network Member",
    sublabel: null,
    color: "#2e7d32",
    bg: "#e8f5e9",
    border: "#a5d6a7",
    icon: "🌐",
  };
};

// ─── ReadMore component ──────────────────────────────────────────────────────
function ReadMore({ text, maxLength = 180 }) {
  const [expanded, setExpanded] = useState(false);
  if (!text) return null;
  if (text.length <= maxLength) {
    return <p style={{ fontSize: "0.82rem", lineHeight: 1.65, margin: 0 }}>{text}</p>;
  }
  return (
    <p style={{ fontSize: "0.82rem", lineHeight: 1.65, margin: 0 }}>
      {expanded ? text : `${text.slice(0, maxLength)}...`}
      <span
        onClick={() => setExpanded(!expanded)}
        style={{ color: "#ff3e43", cursor: "pointer", fontWeight: 600, marginLeft: 4, fontSize: "0.78rem" }}
      >
        {expanded ? " less" : " more"}
      </span>
    </p>
  );
}

function CommentText({ text, maxLength = 120 }) {
  const [expanded, setExpanded] = useState(false);
  if (!text) return null;
  if (text.length <= maxLength) {
    return <p style={{ fontSize: "0.78rem", margin: "2px 0 0", color: "#555" }}>{text}</p>;
  }
  return (
    <p style={{ fontSize: "0.78rem", margin: "2px 0 0", color: "#555" }}>
      {expanded ? text : `${text.slice(0, maxLength)}...`}
      <span
        onClick={() => setExpanded(!expanded)}
        style={{ color: "#ff3e43", cursor: "pointer", fontWeight: 600, marginLeft: 4, fontSize: "0.72rem" }}
      >
        {expanded ? " less" : " more"}
      </span>
    </p>
  );
}

// ─── Image Carousel ───────────────────────────────────────────────────────────
function ImageCarousel({ images }) {
  const [idx, setIdx] = useState(0);
  if (!images || images.length === 0) return null;

  const getImageSrc = (url) => {
    if (!url) return "";
    if (url.startsWith("http")) return url;
    return API_BASE_URL.replace(/\/$/, "") + url;
  };

  return (
    <div style={{ position: "relative", borderRadius: 10, overflow: "hidden" }}>
      <img
        src={getImageSrc(images[idx])}
        alt={`post-${idx}`}
        style={{ width: "100%", height: 260, objectFit: "cover", display: "block" }}
      />
      {images.length > 1 && (
        <>
          <button
            onClick={() => setIdx((i) => (i - 1 + images.length) % images.length)}
            style={{
              position: "absolute", left: 8, top: "50%",
              transform: "translateY(-50%)",
              background: "rgba(0,0,0,0.45)", border: "none",
              borderRadius: "50%", width: 30, height: 30,
              display: "flex", alignItems: "center",
              justifyContent: "center", cursor: "pointer", color: "#fff",
            }}
          ><ChevronLeft size={16} /></button>
          <button
            onClick={() => setIdx((i) => (i + 1) % images.length)}
            style={{
              position: "absolute", right: 8, top: "50%",
              transform: "translateY(-50%)",
              background: "rgba(0,0,0,0.45)", border: "none",
              borderRadius: "50%", width: 30, height: 30,
              display: "flex", alignItems: "center",
              justifyContent: "center", cursor: "pointer", color: "#fff",
            }}
          ><ChevronRight size={16} /></button>
          <div style={{
            position: "absolute", bottom: 8, left: 0, right: 0,
            display: "flex", justifyContent: "center", gap: 5,
          }}>
            {images.map((_, i) => (
              <span
                key={i}
                onClick={() => setIdx(i)}
                style={{
                  width: 7, height: 7, borderRadius: "50%",
                  cursor: "pointer",
                  background: i === idx ? "#fff" : "rgba(255,255,255,0.45)",
                  display: "inline-block",
                }}
              />
            ))}
          </div>
        </>
      )}
    </div>
  );
}

// ─── Main SocialPosts ─────────────────────────────────────────────────────────
export default function SocialPosts() {
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);
  const [openComments, setOpenComments] = useState(null);
  const [commentInputs, setCommentInputs] = useState({});
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [companyDetails, setCompanyDetails] = useState(null);
  const [openEmojiPicker, setOpenEmojiPicker] = useState(null);
  const [shareModalPost, setShareModalPost] = useState(null);
  const [openMenuPostId, setOpenMenuPostId] = useState(null);
  const [ClientIP, setClientIP] = useState("");
  const [CountryName, setCountryName] = useState("");
  // ✅ Per-post investor details + CRM cache
  // { [post_id]: { details: {...}, crmStatus: 'in_crm'|'not_in_crm'|null } }
  const [postInvestorData, setPostInvestorData] = useState({});
  const [postCompanyData, setPostCompanyData] = useState({}); // { [post_id]: { city, state, country } }
  const [crmLoadingIds, setCrmLoadingIds] = useState(new Set());

  // ─── Ref for infinite scroll sentinel ───────────────────────────────────
  const sentinelRef = useRef(null);
  useEffect(() => {
    const getIP = async () => {
      try {
        const res = await fetch("https://ipapi.co/json/");
        const data = await res.json();

        setClientIP(data.ip); // Save this to state
        setCountryName(data.country_name);
      } catch (error) {
        console.error("Failed to fetch IP", error);
      }
    };

    getIP();
  }, []);
  // ─── Close 3-dot menu on outside click ───────────────────────────────────
  useEffect(() => {
    const handleClickOutside = () => setOpenMenuPostId(null);
    document.addEventListener("click", handleClickOutside);
    return () => document.removeEventListener("click", handleClickOutside);
  }, []);

  // ─── User from localStorage ───────────────────────────────────────────────
  const storedUsername = localStorage.getItem("SignatoryLoginData");
  const userLogin = storedUsername ? JSON.parse(storedUsername) : null;
  const SOCIAL_API = API_BASE_URL + "api/user/socialpost/";
  const API_URL = API_BASE_URL + "api/user/";
  const CHAT_API = API_BASE_URL + "api/user/chatmessage";
  const access_token = userLogin?.access_token;

  // ✅ Fetch investor details for a post (lazy — only when needed)
  const fetchPostInvestorData = async (postId, investorId) => {
    if (postInvestorData[postId]) return; // already fetched
    try {
      const [detailRes, crmRes] = await Promise.all([
        axios.post(API_URL + "getInvestorData", { investor_id: investorId }, { headers: { "Content-Type": "application/json" } }),
        axios.post(CHAT_API + "/getInvestorCrmData", { investor_id: investorId, company_id: currentUser.id }, { headers: { "Content-Type": "application/json", "Authorization": `Bearer ${access_token}` } }),
      ]);
      setPostInvestorData(prev => ({
        ...prev,
        [postId]: {
          details: detailRes.data.results?.[0] || null,
          crmStatus: (crmRes.data.success && crmRes.data.in_crm) ? "in_crm" : "not_in_crm",
        }
      }));
    } catch {
      setPostInvestorData(prev => ({ ...prev, [postId]: { details: null, crmStatus: "not_in_crm" } }));
    }
  };

  // ✅ Fetch company location for company posts
  const fetchCompanyLocation = async (postId, companyId) => {
    if (postCompanyData[postId]) return;
    try {
      const res = await axios.post(SOCIAL_API + "company-location", { company_id: companyId });
      if (res.data.success) {
        setPostCompanyData(prev => ({ ...prev, [postId]: res.data.company }));
      }
    } catch { }
  };

  // ✅ Add to CRM
  const handleAddToCrm = async (postId, investorId) => {
    setCrmLoadingIds(prev => new Set(prev).add(postId));
    try {
      await axios.post(CHAT_API + "/addInvestorToCrm", { ClientIP: ClientIP, CountryName: CountryName, investor_id: investorId, company_id: currentUser.id }, { headers: { "Content-Type": "application/json", "Authorization": `Bearer ${access_token}` } });
      setPostInvestorData(prev => ({ ...prev, [postId]: { ...prev[postId], crmStatus: "in_crm" } }));
    } catch { } finally {
      setCrmLoadingIds(prev => { const n = new Set(prev); n.delete(postId); return n; });
    }
  };

  // ✅ Remove from CRM
  const handleRemoveFromCrm = async (postId, investorId) => {
    setCrmLoadingIds(prev => new Set(prev).add(postId));
    try {
      await axios.post(CHAT_API + "/removeInvestorFromCrm", { ClientIP: ClientIP, CountryName: CountryName, investor_id: investorId, company_id: currentUser.id }, { headers: { "Content-Type": "application/json", "Authorization": `Bearer ${access_token}` } });
      setPostInvestorData(prev => ({ ...prev, [postId]: { ...prev[postId], crmStatus: "not_in_crm" } }));
    } catch { } finally {
      setCrmLoadingIds(prev => { const n = new Set(prev); n.delete(postId); return n; });
    }
  };

  // ─── Fetch company details ────────────────────────────────────────────────
  useEffect(() => {
    const getCompanyData = async () => {
      try {
        const res = await axios.post(
          API_URL + "getcompanyData",
          { company_id: userLogin?.companies?.[0]?.id },
          { headers: { "Content-Type": "application/json" } }
        );
        setCompanyDetails(res.data.results?.[0] || null);
      } catch (err) {
        console.error("Error fetching company details:", err);
      }
    };
    if (userLogin?.companies?.[0]?.id) getCompanyData();
  }, []);

  // ─── currentUser ─────────────────────────────────────────────────────────
  const currentUser = {
    id: userLogin?.companies?.[0]?.id,
    type: userLogin?.companies ? "company" : "investor",
    name:
      companyDetails?.company_name ||
      `${userLogin?.first_name || ""} ${userLogin?.last_name || ""}`.trim() ||
      "User",
    image: companyDetails?.company_logo_url || userLogin?.profile_image || null,
  };

  // ─── Fetch posts ──────────────────────────────────────────────────────────
  const fetchPosts = useCallback(async (pageNum = 1, append = false) => {
    if (pageNum === 1) setLoading(true);
    else setLoadingMore(true);

    try {
      const res = await axios.post(SOCIAL_API + "posts", {
        user_id: currentUser.id,
        user_type: currentUser.type,
        page: pageNum,
      });

      if (res.data.success) {
        const incoming = res.data.posts.map(normalizePost);

        // ✅ Agar 10 se kam aaye toh aur posts nahi hain
        if (incoming.length < 10) setHasMore(false);
        else setHasMore(true);

        if (append) {
          setPosts((prev) => {
            // Duplicate avoid karo
            const existingIds = new Set(prev.map((p) => p.id));
            const fresh = incoming.filter((p) => !existingIds.has(p.id));
            return [...prev, ...fresh];
          });
        } else {
          setPosts(incoming);
        }
      }
    } catch (err) {
      console.error("Error fetching posts:", err);
    } finally {
      setLoading(false);
      setLoadingMore(false);
    }
  }, [currentUser.id, currentUser.type]);

  // ─── Initial load ─────────────────────────────────────────────────────────
  useEffect(() => {
    fetchPosts(1, false);
  }, []);

  // ─── IntersectionObserver — infinite scroll ───────────────────────────────
  useEffect(() => {
    if (!sentinelRef.current) return;

    const observer = new IntersectionObserver(
      (entries) => {
        const first = entries[0];
        if (first.isIntersecting && hasMore && !loadingMore && !loading) {
          const nextPage = page + 1;
          setPage(nextPage);
          fetchPosts(nextPage, true);
        }
      },
      { threshold: 0.1 }
    );

    observer.observe(sentinelRef.current);
    return () => observer.disconnect();
  }, [hasMore, loadingMore, loading, page, fetchPosts]);


  // ─── Re-join social room when user id becomes available ──────────────────
  useEffect(() => {
    if (!currentUser?.id) return;
    const sock = getSocket();
    sock.emit("join_social_room", {
      user_id: currentUser.id,
      user_type: currentUser.type,
    });

  }, [currentUser.id]);

  // ─── Socket realtime ──────────────────────────────────────────────────────
  useEffect(() => {
    const sock = getSocket();

    sock.on("social:new_post", (post) => {
      setPosts((prev) => {
        const exists = prev.some((p) => p.id === post.id);
        if (exists) return prev;
        const myId = userLogin?.companies?.[0]?.id;
        const myType = userLogin?.companies ? "company" : "investor";
        if (String(post.author_id) === String(myId) && post.author_type === myType)
          return prev;
        return [normalizePost(post), ...prev];
      });
    });

    sock.on("social:like_update", ({ post_id, likes_count }) => {
      setPosts((prev) =>
        prev.map((p) => (p.id === post_id ? { ...p, likes: likes_count } : p))
      );
    });

    sock.on("social:new_comment", ({ post_id, comment }) => {
      setPosts((prev) =>
        prev.map((p) => {
          if (p.id !== post_id) return p;
          const already = p.commentsList?.some(
            (c) => !String(c.id).startsWith("temp_") && c.id === comment.id
          );
          if (already) return p;
          const hasMyTemp = p.commentsList?.some(
            (c) => String(c.id).startsWith("temp_") &&
              c.text === (comment.text || comment.comment)
          );
          if (hasMyTemp) return p;
          return {
            ...p,
            comments: p.comments + 1,
            commentsList: [
              ...(p.commentsList || []),
              { ...comment, text: comment.text || comment.comment },
            ],
          };
        })
      );
    });

    if (currentUser?.id) {
      // ✅ user-online emit — server social_user_ room join karega
      sock.emit("user-online", {
        user_id: currentUser.id,
        user_type: currentUser.type,
      });
      // Alag se bhi join karo — safety ke liye
      sock.emit("join_social_room", {
        user_id: currentUser.id,
        user_type: currentUser.type,
      });
    }

    // ✅ Follow update — jab koi follow/unfollow kare
    sock.on("social:follow_update", ({ follower_id, follower_type, following_id, following_type, action }) => {

      // Apne posts mein us user ke baare mein followed status update karo
      setPosts((prev) =>
        prev.map((p) => {
          // Agar current user ne follow/unfollow kiya (doosre device/tab se)
          if (
            String(p.author_id) === String(following_id) &&
            p.author_type === following_type
          ) {
            return { ...p, followed: action === "followed" };
          }
          return p;
        })
      );
    });

    // ✅ Real-time follow status update
    sock.on("social:follow_update", ({ follower_id, follower_type, following_id, following_type, action }) => {
      const isNowFollowed = action === "followed";
      setPosts((prev) =>
        prev.map((p) => {
          // Case 1: Main ne follow/unfollow kiya — mere saare posts mein us author ka button update
          if (
            String(follower_id) === String(currentUser.id) &&
            follower_type === currentUser.type &&
            String(p.author_id) === String(following_id) &&
            p.author_type === following_type
          ) {
            return { ...p, followed: isNowFollowed };
          }
          return p;
        })
      );
    });

    // ✅ Pin update — real-time pin/unpin from any device
    sock.on("social:pin_update", ({ post_id, is_pinned }) => {
      setPosts((prev) => {
        const updated = prev.map((p) => ({
          ...p,
          is_pinned: p.id === post_id ? is_pinned : (is_pinned ? false : p.is_pinned),
        }));
        const pinnedPosts = updated.filter((p) => p.is_pinned);
        const restPosts = updated.filter((p) => !p.is_pinned);
        return [...pinnedPosts, ...restPosts];
      });
    });

    return () => {
      sock.off("social:new_post");
      sock.off("social:like_update");
      sock.off("social:new_comment");
      sock.off("social:follow_update");
      sock.off("social:follow_update");
      sock.off("social:pin_update");
    };
  }, []);

  // ─── Pin / Unpin ─────────────────────────────────────────────────────────────
  const handlePin = async (post) => {
    const wasPin = post.is_pinned;
    const nowPin = !wasPin;
    setOpenMenuPostId(null);

    // ✅ Optimistic update + re-sort (pinned post upar aaye)
    setPosts((prev) => {
      const updated = prev.map((p) => ({
        ...p,
        is_pinned: p.id === post.id ? nowPin : (nowPin ? false : p.is_pinned),
      }));
      // Pinned post ko top pe le jao
      const pinnedPosts = updated.filter((p) => p.is_pinned);
      const restPosts = updated.filter((p) => !p.is_pinned);
      return [...pinnedPosts, ...restPosts];
    });

    try {
      const res = await axios.post(SOCIAL_API + "pin", {
        post_id: post.id,
        author_id: currentUser.id,
        author_type: currentUser.type,
      });
      if (!res.data.success) throw new Error("Pin failed");
    } catch {
      // ✅ Revert on error
      setPosts((prev) => {
        const reverted = prev.map((p) => ({
          ...p,
          is_pinned: p.id === post.id ? wasPin : p.is_pinned,
        }));
        const pinnedPosts = reverted.filter((p) => p.is_pinned);
        const restPosts = reverted.filter((p) => !p.is_pinned);
        return [...pinnedPosts, ...restPosts];
      });
    }
  };

  // ─── Like / Unlike ────────────────────────────────────────────────────────
  const handleLike = async (postId) => {
    setPosts((prev) =>
      prev.map((p) => {
        if (p.id !== postId) return p;
        const nowLiked = !p.liked;
        return { ...p, liked: nowLiked, likes: nowLiked ? p.likes + 1 : p.likes - 1 };
      })
    );
    try {
      await axios.post(SOCIAL_API + "posts/like", {
        post_id: postId,
        user_id: currentUser.id,
        user_type: currentUser.type,
      });
    } catch {
      setPosts((prev) =>
        prev.map((p) => {
          if (p.id !== postId) return p;
          return { ...p, liked: !p.liked, likes: p.liked ? p.likes + 1 : p.likes - 1 };
        })
      );
    }
  };

  // ─── Follow / Unfollow ───────────────────────────────────────────────────
  const handleFollow = async (post) => {
    const postId = post.id;
    const targetId = post.author_id;
    const targetType = post.author_type;
    const wasFollowed = post.followed;

    // Optimistic update
    setPosts((prev) =>
      prev.map((p) => (p.id === postId ? { ...p, followed: !wasFollowed } : p))
    );

    try {
      const res = await axios.post(SOCIAL_API + "follow", {
        follower_id: currentUser.id,
        follower_type: currentUser.type,
        following_id: targetId,
        following_type: targetType,
      });

      if (res.data.success) {
        const isNowFollowed = res.data.action === "followed";
        // ✅ API response se confirm state set karo
        // Same author ke saare posts update karo
        setPosts((prev) =>
          prev.map((p) =>
            String(p.author_id) === String(targetId) && p.author_type === targetType
              ? { ...p, followed: isNowFollowed }
              : p
          )
        );
      }
    } catch {
      // Revert on error
      setPosts((prev) =>
        prev.map((p) => (p.id === postId ? { ...p, followed: wasFollowed } : p))
      );
    }
  };

  // ─── Comment submit ───────────────────────────────────────────────────────
  const handleCommentSubmit = async (postId) => {
    const text = commentInputs[postId]?.trim();
    if (!text) return;

    const tempId = `temp_${Date.now()}`;
    const tempComment = {
      id: tempId,
      author: currentUser.name,
      author_image: currentUser.image,
      text,
      created_at: new Date().toISOString(),
      isTemp: true,
    };

    setPosts((prev) =>
      prev.map((p) => {
        if (p.id !== postId) return p;
        return {
          ...p,
          comments: p.comments + 1,
          commentsList: [...(p.commentsList || []), tempComment],
        };
      })
    );
    setCommentInputs((prev) => ({ ...prev, [postId]: "" }));
    setOpenEmojiPicker(null);

    try {
      const res = await axios.post(SOCIAL_API + "posts/comment", {
        post_id: postId,
        comment: text,
        author_id: currentUser.id,
        author_type: currentUser.type,
      });
      if (res.data.success) {
        const realComment = res.data.comment;
        setCommentInputs([]);
        setPosts((prev) =>
          prev.map((p) => {
            if (p.id !== postId) return p;
            return {
              ...p,
              commentsList: p.commentsList.map((c) =>
                c.id === tempId
                  ? { ...realComment, text: realComment.text || realComment.comment }
                  : c
              ),
            };
          })
        );
      }
    } catch {
      setPosts((prev) =>
        prev.map((p) => {
          if (p.id !== postId) return p;
          return {
            ...p,
            comments: p.comments - 1,
            commentsList: p.commentsList.filter((c) => c.id !== tempId),
          };
        })
      );
    }
  };

  // ─── Post created callback ────────────────────────────────────────────────
  const handlePostCreated = (newPost) => {
    setPosts((prev) => [normalizePost(newPost), ...prev]);
  };

  // ─── Toggle comments ─────────────────────────────────────────────────────
  const handleToggleComments = async (postId) => {
    const sock = getSocket();
    if (openComments === postId) {
      sock.emit("leave_post_room", { post_id: postId });
      setOpenComments(null);
    } else {
      if (openComments) sock.emit("leave_post_room", { post_id: openComments });
      sock.emit("join_post_room", { post_id: postId });
      setOpenComments(postId);
      try {
        const res = await axios.post(SOCIAL_API + "posts/comments", {
          post_id: postId,
        });
        if (res.data.success) {
          const fetchedComments = res.data.comments.map((c) => ({
            id: c.id,
            author: c.author || c.author_name || (c.author_type === "company" ? "Company" : "Investor"),
            author_image: c.author_image || null,
            text: c.comment,
            created_at: c.created_at,
          }));
          setPosts((prev) =>
            prev.map((p) =>
              p.id === postId ? { ...p, commentsList: fetchedComments } : p
            )
          );
        }
      } catch (err) {
        console.error("Error fetching comments:", err);
      }
    }
  };

  // ─── Render ───────────────────────────────────────────────────────────────
  return (
    <>
      {/* ── Create post trigger ── */}
      <div className="d-flex align-items-center gap-3">
        <div
          className="d-flex align-items-center gap-3 w-100"
          onClick={() => setShowCreateModal(true)}
          style={{ cursor: "pointer" }}
        >
          <div className="user-profile flex-shrink-0" style={{ position: "relative", overflow: "hidden" }}>
            {currentUser.image ? (
              <img
                src={currentUser.image}
                alt="profile"
                className="w-100 h-100 object-fit-cover"
                onError={(e) => { e.target.style.display = "none"; e.target.nextSibling.style.display = "flex"; }}
              />
            ) : null}
            <div style={{
              display: currentUser.image ? "none" : "flex",
              width: "100%", height: "100%",
              borderRadius: "50%",
              background: "#ff3e43",
              alignItems: "center", justifyContent: "center",
              color: "#fff", fontWeight: 700,
              fontSize: "1rem", textTransform: "uppercase",
              position: "absolute", top: 0, left: 0,
            }}>
              {(currentUser.name || "U").charAt(0)}
            </div>
          </div>
          <div className="w-100">
            <input
              type="text"
              className="serach_input"
              placeholder="Start a post"
              readOnly
            />
          </div>
        </div>

        {/* ✅ Refresh button */}
        <button
          onClick={(e) => {
            e.stopPropagation();
            setPage(1);
            fetchPosts(1, false);
          }}
          title="Refresh posts"
          style={{
            flexShrink: 0,
            background: "none",
            border: "1.5px solid #e5e7eb",
            borderRadius: "50%",
            width: 38, height: 38,
            display: "flex", alignItems: "center", justifyContent: "center",
            cursor: "pointer",
            color: "#6b7280",
            transition: "all 0.2s",
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.borderColor = "#ff3e43";
            e.currentTarget.style.color = "#ff3e43";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.borderColor = "#e5e7eb";
            e.currentTarget.style.color = "#6b7280";
          }}
        >
          <svg
            width="16" height="16"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="2.2"
            strokeLinecap="round"
            strokeLinejoin="round"
          >
            <polyline points="23 4 23 10 17 10" />
            <polyline points="1 20 1 14 7 14" />
            <path d="M3.51 9a9 9 0 0 1 14.85-3.36L23 10M1 14l4.64 4.36A9 9 0 0 0 20.49 15" />
          </svg>
        </button>
      </div>

      {/* ── Loading state (first load) ── */}
      {loading && (
        <div className="text-center py-4">
          <div className="spinner-border spinner-border-sm text-danger" role="status" />
          <p style={{ fontSize: "0.82rem", color: "#aaa", marginTop: 8 }}>Loading posts...</p>
        </div>
      )}

      {/* ── Empty state ── */}
      {!loading && posts.length === 0 && (
        <div className="text-center py-5">
          <p style={{ fontSize: "0.9rem", color: "#aaa" }}>
            No posts yet. Be the first to share something!
          </p>
        </div>
      )}

      {/* ── Posts list ── */}
      {!loading && posts.length > 0 && (
        <div className="row g-4 mt-1">
          {posts.map((post) => (
            <div className="col-12" key={post.id}>
              <div className="post_deisgn shadow-sm">
                <div className="d-flex flex-column gap-3">

                  {/* Header */}
                  <div className="d-flex align-items-center gap-3">
                    <div className="post-profile flex-shrink-0" style={{ position: "relative", overflow: "hidden" }}>
                      {(post.userimage || post.author_image) ? (
                        <img
                          src={post.userimage || post.author_image}
                          alt="profile"
                          className="w-100 h-100 object-fit-cover rounded-circle"
                          onError={(e) => { e.target.style.display = "none"; e.target.nextSibling.style.display = "flex"; }}
                        />
                      ) : null}
                      <div style={{
                        display: (post.userimage || post.author_image) ? "none" : "flex",
                        width: "100%", height: "100%",
                        borderRadius: "50%",
                        background: "#ff3e43",
                        alignItems: "center", justifyContent: "center",
                        color: "#fff", fontWeight: 700,
                        fontSize: "1rem", textTransform: "uppercase",
                        position: "absolute", top: 0, left: 0,
                      }}>
                        {(post.name || post.author_name || "?").charAt(0)}
                      </div>
                    </div>
                    <div style={{ flex: 1 }}>
                      <div className="d-flex align-items-center gap-2 flex-wrap">
                        <h4 style={{ margin: 0 }}>
                          {post.name || post.author_name || (post.author_type === "company" ? "Company" : "Investor")}
                        </h4>
                        {/* ✅ Investor badge only */}
                        {post.author_type === "investor" && (
                          <span style={{
                            fontSize: "0.65rem", fontWeight: 600,
                            padding: "2px 8px", borderRadius: 20,
                            background: "#e8f5e9",
                            color: "#2e7d32",
                            border: "1px solid #a5d6a7",
                          }}>
                            👤 Investor
                          </span>
                        )}
                        {/* ✅ Sender category badge */}
                        {(() => {
                          const info = getSenderInfo(post);
                          if (!info) return null;
                          const isPortfolio = post.sender_category === "portfolio_company";
                          const badge = (
                            <span style={{
                              fontSize: "0.6rem", fontWeight: 600,
                              padding: "2px 8px", borderRadius: 20,
                              background: info.bg,
                              color: info.color,
                              border: `1px solid ${info.border}`,
                              display: "flex", alignItems: "center", gap: 3,
                              whiteSpace: "nowrap",
                              cursor: isPortfolio ? "pointer" : "default",
                              textDecoration: isPortfolio ? "underline dotted" : "none",
                            }}
                              onClick={isPortfolio ? (e) => {
                                e.stopPropagation();
                                window.open(`/investor/company-portfolio/${post.author_id}`, "_blank");
                              } : undefined}
                              title={isPortfolio ? "View Portfolio Company" : undefined}
                            >
                              {info.icon} {info.label}
                              {info.sublabel && (
                                <span style={{ opacity: 0.75, fontWeight: 400 }}>
                                  · {info.sublabel}
                                </span>
                              )}
                            </span>
                          );
                          return badge;
                        })()}
                      </div>
                      {/* ✅ Pinned badge */}
                      {post.is_pinned && (
                        <span style={{
                          fontSize: "0.6rem", fontWeight: 600,
                          padding: "2px 7px", borderRadius: 20,
                          background: "#fff8e1", color: "#f57f17",
                          border: "1px solid #ffe082",
                          display: "inline-flex", alignItems: "center", gap: 3,
                          marginTop: 3,
                        }}>
                          📌 Pinned
                        </span>
                      )}
                      {/* ✅ Investor post — type + location + CRM (company user ke liye) */}
                      {currentUser.type === "company" && post.author_type === "investor" && (() => {
                        if (!postInvestorData[post.id]) fetchPostInvestorData(post.id, post.author_id);
                        const inv = postInvestorData[post.id];
                        return (
                          <div style={{ display: "flex", alignItems: "center", gap: 5, flexWrap: "wrap", marginTop: 3 }}>
                            {inv?.details?.type_of_investor && (
                              <span style={{ fontSize: "0.6rem", color: "#6b7280", background: "#f3f4f6", padding: "1px 7px", borderRadius: 20, border: "1px solid #e5e7eb" }}>
                                {inv.details.type_of_investor}
                              </span>
                            )}
                            {inv?.details && (inv.details.city || inv.details.state || inv.details.country) && (
                              <span style={{ fontSize: "0.6rem", color: "#6b7280", display: "flex", alignItems: "center", gap: 2 }}>
                                📍 {[inv.details.city, inv.details.state, inv.details.country].filter(Boolean).join(", ")}
                              </span>
                            )}
                            {inv?.crmStatus === "in_crm" && (
                              <span style={{ fontSize: "0.6rem", color: "#22c55e", fontWeight: 600 }}>● In Contact CRM</span>
                            )}
                          </div>
                        );
                      })()}

                      {/* ✅ Company post — location from API */}
                      {post.author_type === "company" && (() => {
                        if (!postCompanyData[post.id]) fetchCompanyLocation(post.id, post.author_id);
                        const comp = postCompanyData[post.id];
                        const loc = comp ? [comp.company_city, comp.company_state, comp.company_country].filter(Boolean).join(", ") : "";
                        return loc ? (
                          <span style={{ fontSize: "0.6rem", color: "#6b7280", display: "inline-flex", alignItems: "center", gap: 2, marginTop: 3 }}>
                            📍 {loc}
                          </span>
                        ) : null;
                      })()}

                      {post.role && <h5 style={{ margin: "2px 0 0" }}>{post.role}</h5>}
                      {post.status && <h5 style={{ margin: "2px 0 0" }}>({post.status})</h5>}
                    </div>
                    <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                      <span style={{ fontSize: "0.72rem", color: "#aaa", whiteSpace: "nowrap" }}>
                        {timeAgo(post.created_at)}
                      </span>
                      {/* ✅ 3-dot menu — sirf apni post pe */}
                      {((String(currentUser.id) === String(post.author_id) && currentUser.type === post.author_type) || (currentUser.type === 'company' && post.author_type === 'investor')) && (
                        <div style={{ position: "relative" }}>
                          <button
                            onClick={(e) => { e.stopPropagation(); setOpenMenuPostId(openMenuPostId === post.id ? null : post.id); }}
                            style={{ background: "none", border: "none", cursor: "pointer", color: "#bbb", padding: "2px 4px", fontSize: "1rem", lineHeight: 1 }}
                          >
                            ···
                          </button>
                          {openMenuPostId === post.id && (
                            <div style={{
                              position: "absolute", right: 0, top: "110%", zIndex: 100,
                              background: "#fff", borderRadius: 10,
                              boxShadow: "0 4px 20px rgba(0,0,0,0.12)",
                              border: "1px solid #f0f0f0", minWidth: 160, overflow: "hidden",
                            }}>
                              {/* Pin — sirf apni post */}
                              {((String(currentUser.id) === String(post.author_id) && currentUser.type === post.author_type) || (currentUser.type === 'company' && post.author_type === 'investor')) && (
                                <button
                                  onClick={() => handlePin(post)}
                                  style={{ width: "100%", padding: "10px 16px", textAlign: "left", background: "none", border: "none", cursor: "pointer", fontSize: "0.82rem", color: "#333", display: "flex", alignItems: "center", gap: 8 }}
                                  onMouseEnter={(e) => e.currentTarget.style.background = "#f8f9fa"}
                                  onMouseLeave={(e) => e.currentTarget.style.background = "none"}
                                >
                                  📌 {post.is_pinned ? "Unpin" : "Pin"}
                                </button>
                              )}
                              {/* CRM — sirf company + investor post */}
                              {currentUser.type === "company" && post.author_type === "investor" && (() => {
                                const inv = postInvestorData[post.id];
                                const isLoading = crmLoadingIds.has(post.id);
                                if (!inv) return null;
                                return inv.crmStatus === "in_crm" ? (
                                  <button
                                    onClick={() => { handleRemoveFromCrm(post.id, post.author_id); setOpenMenuPostId(null); }}
                                    disabled={isLoading}
                                    style={{ width: "100%", padding: "9px 16px", textAlign: "left", background: "none", border: "none", borderTop: "1px solid #fee2e2", cursor: "pointer", fontSize: "0.8rem", color: "#ef4444", display: "flex", alignItems: "center", gap: 7, whiteSpace: "nowrap" }}
                                    onMouseEnter={(e) => e.currentTarget.style.background = "#fff5f5"}
                                    onMouseLeave={(e) => e.currentTarget.style.background = "none"}
                                  >
                                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="3 6 5 6 21 6" /><path d="M19 6l-1 14H6L5 6" /><path d="M9 6V4h6v2" /></svg>
                                    Remove from CRM
                                  </button>
                                ) : (
                                  <button
                                    onClick={() => { handleAddToCrm(post.id, post.author_id); setOpenMenuPostId(null); }}
                                    disabled={isLoading}
                                    style={{ width: "100%", padding: "9px 16px", textAlign: "left", background: "none", border: "none", borderTop: "1px solid #dcfce7", cursor: "pointer", fontSize: "0.8rem", color: "#16a34a", display: "flex", alignItems: "center", gap: 7, whiteSpace: "nowrap" }}
                                    onMouseEnter={(e) => e.currentTarget.style.background = "#f0fdf4"}
                                    onMouseLeave={(e) => e.currentTarget.style.background = "none"}
                                  >
                                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><line x1="12" y1="5" x2="12" y2="19" /><line x1="5" y1="12" x2="19" y2="12" /></svg>
                                    Add to CRM
                                  </button>
                                );
                              })()}
                            </div>
                          )}
                        </div>
                      )}
                    </div>
                  </div>

                  {/* Content */}
                  {post.content && <ReadMore text={post.content} />}
                  {!post.content && post.message && <ReadMore text={post.message} />}

                  {/* Images */}
                  <ImageCarousel images={post.images} />

                  {/* Action bar */}
                  <div className="d-flex align-items-center justify-content-between flex-wrap gap-3 pt-2 border-top">
                    <div className="d-flex gap-3">
                      <button
                        className="btn btn-link p-0 d-flex align-items-center gap-2"
                        style={{ color: post.liked ? "#ff3e43" : "#6c757d", textDecoration: "none" }}
                        onClick={() => handleLike(post.id)}
                      >
                        <ThumbsUp size={18} strokeWidth={1.5} fill={post.liked ? "#ff3e43" : "none"} />
                        <span style={{ fontSize: "0.8rem" }}>{post.likes}</span>
                      </button>
                      <button
                        className="btn btn-link p-0 text-muted d-flex align-items-center gap-2"
                        style={{ textDecoration: "none" }}
                        onClick={() => handleToggleComments(post.id)}
                      >
                        <MessageCircle size={18} strokeWidth={1.5} fill={openComments === post.id ? "#e9ecef" : "none"} />
                        <span style={{ fontSize: "0.8rem" }}>{post.comments}</span>
                      </button>
                      <button
                        className="btn btn-link p-0 text-muted d-flex align-items-center gap-2"
                        style={{ textDecoration: "none" }}
                        onClick={() => setShareModalPost(post)}
                      >
                        <Share2 size={18} strokeWidth={1.5} />
                      </button>
                    </div>
                    {currentUser.id !== post.author_id && (
                      <button
                        className="btn px-3 py-1 rounded"
                        style={{
                          backgroundColor: post.followed ? "#e9ecef" : "#ff3e43",
                          color: post.followed ? "#333" : "#fff",
                          fontSize: "0.78rem", border: "none", transition: "all 0.2s",
                        }}
                        onClick={() => handleFollow(post)}
                      >
                        {post.followed ? "Following" : `Follow ${post.name || post.author_name || ""}`}
                      </button>
                    )}
                  </div>

                  {/* Comments section */}
                  {openComments === post.id && (
                    <div style={{ borderTop: "1px solid #f0f0f0", paddingTop: 12 }}>
                      {post.commentsList?.length > 0 ? (
                        <div style={{ maxHeight: 200, overflowY: "auto", display: "flex", flexDirection: "column", gap: 8, marginBottom: 12 }}>
                          {post.commentsList.map((c) => (
                            <div key={c.id} style={{ background: "#f8f9fa", borderRadius: 8, padding: "8px 12px", display: "flex", gap: 8, alignItems: "flex-start" }}>
                              <div style={{ width: 26, height: 26, borderRadius: "50%", flexShrink: 0, position: "relative", overflow: "hidden" }}>
                                {c.author_image ? (
                                  <img
                                    src={c.author_image}
                                    style={{ width: "100%", height: "100%", objectFit: "cover", borderRadius: "50%" }}
                                    alt="commenter"
                                    onError={(e) => { e.target.style.display = "none"; e.target.nextSibling.style.display = "flex"; }}
                                  />
                                ) : null}
                                <div style={{
                                  display: c.author_image ? "none" : "flex",
                                  width: "100%", height: "100%",
                                  borderRadius: "50%", background: "#ff3e43",
                                  alignItems: "center", justifyContent: "center",
                                  color: "#fff", fontWeight: 700,
                                  fontSize: "0.65rem", textTransform: "uppercase",
                                  position: "absolute", top: 0, left: 0,
                                }}>
                                  {(c.author || "?").charAt(0)}
                                </div>
                              </div>
                              <div style={{ flex: 1 }}>
                                <span style={{ fontSize: "0.75rem", fontWeight: 600, color: "#333" }}>{c.author}</span>
                                <CommentText text={c.text || c.comment} />
                              </div>
                              <span style={{ fontSize: "0.7rem", color: "#bbb", whiteSpace: "nowrap", paddingTop: 2 }}>
                                {timeAgo(c.created_at)}
                              </span>
                            </div>
                          ))}
                        </div>
                      ) : (
                        <p style={{ fontSize: "0.78rem", color: "#bbb", marginBottom: 12 }}>No comments yet. Be the first!</p>
                      )}
                      <div style={{ display: "flex", gap: 8, alignItems: "center", position: "relative" }}>
                        <input
                          type="text"
                          className="form-control"
                          style={{ fontSize: "0.8rem", borderRadius: 20 }}
                          placeholder="Write a comment..."
                          value={commentInputs[post.id] || ""}
                          onChange={(e) => setCommentInputs((prev) => ({ ...prev, [post.id]: e.target.value }))}
                          onKeyDown={(e) => { if (e.key === "Enter") handleCommentSubmit(post.id); }}
                        />
                        <div style={{ position: "relative" }}>
                          <button
                            onClick={() => setOpenEmojiPicker(openEmojiPicker === post.id ? null : post.id)}
                            style={{ background: "none", border: "none", cursor: "pointer", color: "#aaa", display: "flex", alignItems: "center", padding: 4 }}
                          >
                            😊
                          </button>
                          {openEmojiPicker === post.id && (
                            <div style={{ position: "absolute", bottom: "44px", right: 0, zIndex: 999 }}>
                              <EmojiPicker
                                onEmojiClick={(emojiData) => {
                                  setCommentInputs((prev) => ({ ...prev, [post.id]: (prev[post.id] || "") + emojiData.emoji }));
                                }}
                                height={350} width={300}
                                searchDisabled={false}
                                skinTonesDisabled
                                previewConfig={{ showPreview: false }}
                              />
                            </div>
                          )}
                        </div>
                        <button
                          onClick={() => handleCommentSubmit(post.id)}
                          style={{
                            background: "#ff3e43", border: "none", borderRadius: "50%",
                            width: 36, height: 36, minWidth: 36,
                            display: "flex", alignItems: "center", justifyContent: "center",
                            cursor: "pointer", color: "#fff",
                          }}
                        ><Send size={14} /></button>
                      </div>
                    </div>
                  )}

                </div>
              </div>
            </div>
          ))}

          {/* ── Infinite scroll sentinel ── */}
          <div ref={sentinelRef} style={{ height: 1 }} />

          {/* ── Loading more indicator ── */}
          {loadingMore && (
            <div className="col-12 text-center py-3">
              <div className="spinner-border spinner-border-sm text-danger" role="status" />
              <p style={{ fontSize: "0.78rem", color: "#aaa", marginTop: 6 }}>Loading more posts...</p>
            </div>
          )}


        </div>
      )}

      {/* ── Share Modal ── */}
      {shareModalPost && (
        <ShareModal
          isOpen={!!shareModalPost}
          onClose={() => setShareModalPost(null)}
          post={shareModalPost}
          currentUser={currentUser}
        />
      )}

      {/* ── Create Post Modal ── */}
      {showCreateModal && (
        <CreatePostModal
          onClose={() => setShowCreateModal(false)}
          onSubmit={handlePostCreated}
          currentUser={currentUser}
        />
      )}
    </>
  );
}